    # --- ADVANCED SERVICES (DHCP, DNS) ---
    {"text": "¿Para qué sirve el 'DHCP Relay Agent'?", "option_a": "Para dar IPs más rápido", "option_b": "Para permitir que un cliente obtenga una IP de un servidor DHCP situado en una subred diferente", "option_c": "Para bloquear el DHCP", "option_d": "Un tipo de router wifi", "correct_answer": "b", "difficulty": "medium", "explanation": "Los routers normalmente no pasan tráfico broadcast; el relay convierte el broadcast DHCP del cliente en unicap hacia el servidor."},
    {"text": "¿Qué es el 'DHCP Snooping'?", "option_a": "Espiar las IPs de los vecinos", "option_b": "Característica de seguridad del switch que bloquea servidores DHCP no autorizados (rogue)", "option_c": "Un virus de red", "option_d": "Un comando de Linux", "correct_answer": "b", "difficulty": "hard", "explanation": "Define puertos como 'confiables' e 'inconfiables'; solo los confiables pueden enviar ofertas de IP."},
    {"text": "¿Qué tipo de registro DNS se usa para servicios específicos como controladores de dominio o VoIP?", "option_a": "A", "option_b": "MX", "option_c": "SRV", "option_d": "TXT", "correct_answer": "c", "difficulty": "hard", "explanation": "El registro SRV (Service) define el nombre del host y el puerto para servicios específicos."},
    {"text": "¿Qué registro DNS se utiliza comúnmente para validar la propiedad de un dominio o configurar SPF (seguridad de email)?", "option_a": "CNAME", "option_b": "AAAA", "option_c": "TXT", "option_d": "PTR", "correct_answer": "c", "difficulty": "medium", "explanation": "Permite introducir texto arbitrario legible por máquinas para diversas verificaciones."},
    {"text": "¿Qué es un 'Recursive Query' en DNS?", "option_a": "Una consulta que se repite", "option_b": "El cliente pide al servidor DNS que haga todo el trabajo de resolución hasta encontrar la IP final", "option_c": "Un error de red", "option_d": "Un virus", "correct_answer": "b", "difficulty": "hard", "explanation": "Es la consulta estándar que hace un PC a su servidor DNS local."},

