    {"text": "¿Qué protocolo es el estándar para el control de acceso a la red basado en puertos (NAC)?", "option_a": "802.1Q", "option_b": "802.1X", "option_c": "802.11ac", "option_d": "802.3ad", "correct_answer": "b", "difficulty": "hard", "explanation": "Permite que un puerto de switch permanezca bloqueado hasta que el usuario se autentique contra un servidor RADIUS."},
    {"text": "¿Qué es un 'Captive Portal'?", "option_a": "Un portal mágico", "option_b": "Página web que aparece al conectarse a una red WiFi (normalmente pública) para autenticarse o aceptar términos", "option_c": "Un error de navegación", "option_d": "Un firewall físico", "correct_answer": "b", "difficulty": "easy", "explanation": "Muy típico en hoteles, aeropuertos y cafeterías."},
    {"text": "¿Qué es el 'BYOD' (Bring Your Own Device)?", "option_a": "Llevar comida al trabajo", "option_b": "Política empresarial que permite a los empleados usar sus propios dispositivos personales en la red corporativa", "option_c": "Un virus de red", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "easy", "explanation": "Supone un reto extra de seguridad para los administradores de red."},

    # --- MODERN WAN & SD-WAN ---
    {"text": "¿Qué es el SD-WAN?", "option_a": "Un cable de fibra muy largo", "option_b": "Gestión de redes WAN mediante software, permitiendo usar múltiples enlaces (fibra, 4G, satélite) de forma inteligente", "option_c": "Un router de los años 90", "option_d": "Un tipo de wifi", "correct_answer": "b", "difficulty": "medium", "explanation": "Permite ahorrar costes y mejorar el rendimiento de aplicaciones en la nube al no depender de enlaces MPLS caros."},
    {"text": "¿Qué es el 'Orchestrator' en una arquitectura SD-WAN?", "option_a": "Un músico de red", "option_b": "Panel central de gestión desde donde se definen todas las políticas y configuraciones de la red global", "option_c": "Un virus", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "medium", "explanation": "Permite configurar miles de oficinas desde un solo sitio en minutos."},

    # --- OPTICAL NETWORKING ---
    {"text": "¿Qué significa DWDM?", "option_a": "Digital Wave Data Mode", "option_b": "Dense Wavelength Division Multiplexing (multiplexación por división de longitud de onda densa)", "option_c": "Data Wire Digital Monitor", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "hard", "explanation": "Permite enviar cientos de canales de datos por un solo hilo de fibra óptica usando diferentes 'colores' (longitudes de onda)."},
