    # --- FINAL MIXED REVIEW ---
    {"text": "¿Qué es el 'Any IP' (0.0.0.0/0)?", "option_a": "Una IP prohibida", "option_b": "Representación de la ruta por defecto (todas las redes posibles)", "option_c": "El nombre del servidor DNS", "option_d": "Un error de sintaxis", "correct_answer": "b", "difficulty": "easy", "explanation": "Se usa en las tablas de rutas para enviar el tráfico que no encaja en ninguna ruta específica."},
    {"text": "¿Qué puerto utiliza el protocolo SNMP para recibir Traps?", "option_a": "161", "option_b": "162", "option_c": "443", "option_d": "22", "correct_answer": "b", "difficulty": "hard", "explanation": "Consultas al puerto 161; Recepción de trampas (traps) al 162."},
    {"text": "¿Qué es un 'Top-of-Rack' (ToR) switch?", "option_a": "El mejor switch de la empresa", "option_b": "Switch situado en la parte superior de un rack que conecta todos los servidores de ese rack", "option_c": "Un switch de exterior", "option_d": "Un router con wifi", "correct_answer": "b", "difficulty": "medium", "explanation": "Diseño común en centros de datos para minimizar el cableado horizontal."},
    {"text": "¿Qué significa que un switch es 'Non-blocking'?", "option_a": "Que no tiene candados", "option_b": "Que tiene suficiente ancho de banda interno para procesar el tráfico de todos sus puertos a máxima velocidad a la vez", "option_c": "Que no tiene firewall", "option_d": "Que está siempre encendido", "correct_answer": "b", "difficulty": "hard", "explanation": "Garantiza que el switch no sea un cuello de botella por su arquitectura interna."},
    {"text": "¿Qué es el 'Backplane' de un switch?", "option_a": "La parte de atrás", "option_b": "Sistema de comunicación interno que conecta todos los puertos del switch", "option_c": "Un manual de red", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "medium", "explanation": "Su capacidad define cuántos gigabits por segundo puede mover el switch internamente."},
    {"text": "¿Qué es un 'Loopback Interface' en un router?", "option_a": "Un cable que vuelve", "option_b": "Interfaz virtual siempre activa (UP) usada para propósitos de gestión y protocolos de enrutamiento", "option_c": "Un error de hardware", "option_d": "El puerto de consola", "correct_answer": "b", "difficulty": "medium", "explanation": "Muy útil para que el router siempre sea accesible por una IP fija aunque fallen los enlaces físicos."},
    {"text": "¿Qué es el 'HSRP' (Hot Standby Router Protocol)?", "option_a": "Un protocolo muy caliente", "option_b": "Protocolo de redundancia de gateway (Cisco) que permite que dos routers actúen como uno solo virtual", "option_c": "Un virus de red", "option_d": "Un tipo de fibra", "correct_answer": "b", "difficulty": "hard", "explanation": "Si el router principal falla, el secundario toma la IP virtual instantáneamente sin que los usuarios lo noten."},
    {"text": "¿Qué significa el término 'Throughput'?", "option_a": "La cantidad de cables", "option_b": "La cantidad real de datos que se transmiten exitosamente por la red en un tiempo dado", "option_c": "La velocidad de la luz", "option_d": "Un error de red", "correct_answer": "b", "difficulty": "easy", "explanation": "A diferencia del ancho de banda (teórico), el throughput es la velocidad real percibida."},
    {"text": "¿Qué es la 'Segmentación de Red'?", "option_a": "Cortar los cables", "option_b": "Dividir la red en trozos más pequeños para mejorar la seguridad y el rendimiento", "option_c": "Hacer un backup", "option_d": "Un tipo de wifi", "correct_answer": "b", "difficulty": "easy", "explanation": "Evita que un problema en un departamento afecte a toda la empresa."},
    {"text": "¿Qué es un 'Transparent Firewall'?", "option_a": "Un firewall de cristal", "option_b": "Firewall que opera en Capa 2 (como un puente) y no necesita IPs en sus puertos; es invisible para la red", "option_c": "Un error de configuración", "option_d": "Un firewall que no bloquea nada", "correct_answer": "b", "difficulty": "hard", "explanation": "Ideal para añadir seguridad a redes existentes sin cambiar el direccionamiento IP."},
    {"text": "¿Qué es el 'Packet Loss'?", "option_a": "Perder el paquete de correos", "option_b": "Cuando uno o más paquetes de datos no llegan a su destino a través de la red", "option_c": "Un error de disco", "option_d": "Un tipo de enchufe", "correct_answer": "b", "difficulty": "easy", "explanation": "Causado normalmente por saturación, ruidos o fallos de hardware; degrada mucho la calidad de la conexión."},
    {"text": "¿Qué es el 'Full-Stack' en redes?", "option_a": "Un programador que sabe de todo", "option_b": "Conocimiento de todas las capas de red, desde el cable físico hasta la seguridad y automatización", "option_c": "Un tipo de servidor", "option_d": "Un manual de Cisco", "correct_answer": "b", "difficulty": "medium", "explanation": "Perfil de ingeniero muy demandado que entiende la red de forma holística."},
    {"text": "¿Qué es el 'Air Gap'?", "option_a": "Aire acondicionado para el router", "option_b": "Medida de seguridad que consiste en aislar físicamente una red de cualquier otra red externa o internet", "option_c": "Un hueco en el rack", "option_d": "Un error de wifi", "correct_answer": "b", "difficulty": "medium", "explanation": "Usado en entornos críticos como centrales nucleares o sistemas de defensa."},
    {"text": "¿Qué es un 'Zero-Day exploit' en redes?", "option_a": "Un ataque que dura un día", "option_b": "Ataque que aprovecha una vulnerabilidad desconocida hasta el momento por el fabricante", "option_c": "Un error de reloj del router", "option_d": "Un tipo de cable nuevo", "correct_answer": "b", "difficulty": "medium", "explanation": "Son extremadamente peligrosos porque no existen parches ni firmas de antivirus para detectarlos aún."},
    {"text": "¿Qué es el 'Port Forwarding'?", "option_a": "Escribir puertos de forma rápida", "option_b": "Técnica que permite a un equipo externo acceder a un servicio interno a través de un puerto específico del router", "option_c": "Un error de red", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "easy", "explanation": "Muy usado para cámaras de seguridad, servidores web domésticos o juegos."},
    {"text": "¿Qué es un 'Jump Server' (o Bastion Host)?", "option_a": "Un servidor que salta", "option_b": "Equipo seguro usado como único punto de entrada para administrar otros equipos en una red privada", "option_c": "Un virus", "option_d": "Un router de backup", "correct_answer": "b", "difficulty": "medium", "explanation": "Añade una capa extra de seguridad; solo se permite SSH al Jump Server."},
    {"text": "¿Qué es el 'Dark Fiber' (Fibra Oscura)?", "option_a": "Fibra que no funciona", "option_b": "Hilos de fibra ya instalados pero que todavía no están en uso por ningún operador", "option_c": "Fibra negra", "option_d": "Un error de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Las empresas pueden alquilar estos hilos 'oscuros' para iluminarlos con sus propios equipos."},
    {"text": "¿Qué es un 'Collision Domain'?", "option_a": "Un área de accidentes", "option_b": "Segmento de red donde puede ocurrir una colisión de paquetes si dos nodos transmiten a la vez", "option_c": "Un sitio web", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "easy", "explanation": "Los hubs tienen un solo dominio de colisión; los switches crean un dominio por cada puerto."},
    {"text": "¿Qué es un 'Broadcast Domain'?", "option_a": "Un área de radio", "option_b": "Área de la red hasta donde llega un paquete de difusión (broadcast)", "option_c": "Un servidor DNS", "option_d": "Un tipo de índice", "correct_answer": "b", "difficulty": "easy", "explanation": "Normalmente delimitado por un router o una VLAN."},
    {"text": "¿Qué es el 'Half-Duplex'?", "option_a": "Comunicación en un solo sentido", "option_b": "Comunicación en ambos sentidos pero no al mismo tiempo (como un walkie-talkie)", "option_c": "Comunicación muy rápida", "option_d": "Un error de red", "correct_answer": "b", "difficulty": "easy", "explanation": "Típico de redes antiguas con Hubs o WiFi."},
