    {"text": "¿Qué es un 'Patch Panel'?", "option_a": "Un panel de parches para ropa", "option_b": "Dispositivo pasivo que centraliza todas las conexiones de red de un edificio en el rack", "option_c": "Un router de 48 puertos", "option_d": "Un manual de configuración", "correct_answer": "b", "difficulty": "easy", "explanation": "Permite organizar y etiquetar fácilmente el cableado estructurado."},
    {"text": "¿Qué es el 'PoE' (Power over Ethernet)?", "option_a": "Poder sobre internet", "option_b": "Tecnología que permite alimentar eléctricamente dispositivos a través del cable de red (ej: cámaras, teléfonos IP)", "option_c": "Un virus de red", "option_d": "Un tipo de batería", "correct_answer": "b", "difficulty": "easy", "explanation": "Elimina la necesidad de tener un enchufe cerca de cada dispositivo."},
    {"text": "¿Qué significa que una dirección IP es 'Unicast'?", "option_a": "Que va dirigida a todos", "option_b": "Que va dirigida a un único dispositivo específico", "option_c": "Que es aleatoria", "option_d": "Que es secreta", "correct_answer": "b", "difficulty": "easy", "explanation": "Es el tipo de tráfico más común (punto a punto)."},
    {"text": "¿Qué es el 'IPv4 Depletion'?", "option_a": "El fin del mundo", "option_b": "Agotamiento de las direcciones IPv4 públicas disponibles en el mundo", "option_c": "Borrar internet", "option_d": "Un tipo de backup", "correct_answer": "b", "difficulty": "easy", "explanation": "Es la razón principal por la que necesitamos migrar a IPv6."},
    {"text": "¿Qué protocolo utiliza el puerto 25?", "option_a": "HTTP", "option_b": "SMTP", "option_c": "FTP", "option_d": "SSH", "correct_answer": "b", "difficulty": "easy", "explanation": "Puerto estándar para el envío de correo electrónico (SMTP)."},
    {"text": "¿Qué hace el comando 'ping -t' en Windows?", "option_a": "Mide el tiempo", "option_b": "Hace pings infinitos hasta que el usuario lo detiene (Ctrl+C)", "option_c": "Lanza el ping rápido", "option_d": "Un error de sintaxis", "correct_answer": "b", "difficulty": "easy", "explanation": "Muy útil para ver cuándo vuelve un equipo tras un reinicio."},
    {"text": "En una red /24, ¿cuál es la primera IP utilizable tras la dirección de red .0?", "option_a": ".0", "option_b": ".1", "option_c": ".254", "option_d": ".255", "correct_answer": "b", "difficulty": "easy", "explanation": "Normalmente la .1 se reserva para el Router (Gateway)."},
    {"text": "¿Qué es el 'TTL' en el contexto de DNS?", "option_a": "Todo Tiempo Libre", "option_b": "Time To Live: tiempo que un registro DNS puede estar en caché antes de ser consultado de nuevo", "option_c": "Velocidad del servidor", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Si cambias la IP de tu web, el TTL define cuánto tardará el resto del mundo en ver el cambio."},
    {"text": "¿Qué es un 'A Record' en DNS?", "option_a": "Un disco de música", "option_b": "Registro que asocia un nombre de dominio a una dirección IPv4", "option_c": "Un backup", "option_d": "Un error de DNS", "correct_answer": "b", "difficulty": "easy", "explanation": "Es el tipo de registro más básico y usado."},
    {"text": "¿Qué es un 'AAAA Record' en DNS?", "option_a": "Un grito", "option_b": "Registro que asocia un nombre de dominio a una dirección IPv6", "option_c": "Un tipo de pila", "option_d": "Un virus", "correct_answer": "b", "difficulty": "easy", "explanation": "Equivalente al registro A pero para el protocolo IPv6."},
    {"text": "¿Qué es un 'CNAME' en DNS?", "option_a": "Un nombre falso", "option_b": "Alias que apunta un nombre de dominio a otro nombre de dominio", "option_c": "Una dirección IP", "option_d": "Un error de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Útil para tener varios nombres (ej: shop.empresa.com) apuntando al mismo sitio (www.empresa.com)."},
    {"text": "¿Qué es un 'MX Record' en DNS?", "option_a": "Mix de datos", "option_b": "Mail Exchange: indica qué servidor se encarga de recibir los correos del dominio", "option_c": "Un cifrado", "option_d": "Una IP de México", "correct_answer": "b", "difficulty": "easy", "explanation": "Sin este registro, no podríamos recibir correos en nuestro propio dominio."},
    {"text": "¿Qué herramienta permite verificar la configuración de red en un Mac (terminal)?", "option_a": "ipconfig", "option_b": "ifconfig (o networksetup)", "option_c": "netstat", "option_d": "ping", "correct_answer": "b", "difficulty": "easy", "explanation": "Mac, al ser basado en Unix, comparte muchas herramientas con Linux."},
    {"text": "¿Qué significa que una red es de 'Topología en Estrella'?", "option_a": "Que los cables tienen forma de estrella", "option_b": "Todos los equipos se conectan a un nodo central (Switch)", "option_c": "Que es una red espacial", "option_d": "Un error de diseño", "correct_answer": "b", "difficulty": "easy", "explanation": "Es la topología más común hoy día en redes locales."},
    {"text": "¿Qué significa que una red es de 'Topología en Malla' (Mesh)?", "option_a": "Que está rota", "option_b": "Todos los nodos están conectados entre sí, ofreciendo máxima redundancia", "option_c": "Que es una red de pesca", "option_d": "Un tipo de wifi", "correct_answer": "b", "difficulty": "medium", "explanation": "Muy usado en redes militares y sistemas WiFi modernos para cubrir grandes áreas."},
    {"text": "¿Para qué sirve un 'Repeater' (Repetidor)?", "option_a": "Para repetir curso", "option_b": "Recibe una señal débil, la regenera y la vuelve a transmitir para ampliar el alcance", "option_c": "Un switch de 2 puertos", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "easy", "explanation": "Usado para extender el radio de acción de una red inalámbrica."},
    {"text": "¿Qué es el 'Band Steering' en un router WiFi?", "option_a": "Conducir la banda", "option_b": "Función que mueve automáticamente a un dispositivo de la saturada banda de 2.4GHz a la de 5GHz", "option_c": "Un tipo de cifrado", "option_d": "Un error de señal", "correct_answer": "b", "difficulty": "medium", "explanation": "Mejora la experiencia del usuario sin que tenga que hacer nada."},
    {"text": "¿Qué es el 'Roaming' en WiFi?", "option_a": "Pagar más por el móvil", "option_b": "Capacidad de un dispositivo de cambiar de un punto de acceso a otro sin perder la conexión", "option_c": "Un virus", "option_d": "Un tipo de antena", "correct_answer": "b", "difficulty": "medium", "explanation": "Vital en oficinas grandes con muchos puntos de acceso."},
    {"text": "¿Qué significa 'SSID Broadcast'?", "option_a": "Cifrar el nombre", "option_b": "Que el router emite el nombre de la red para que sea visible por todos", "option_c": "Que la red es secreta", "option_d": "Un error de wifi", "correct_answer": "b", "difficulty": "easy", "explanation": "Se puede desactivar por 'seguridad' (aunque es fácil de saltar)."},
    {"text": "¿Qué es el 'WPS' (Wi-Fi Protected Setup)?", "option_a": "Un firewall wifi", "option_b": "Método para conectar dispositivos pulsando un botón, pero con graves fallos de seguridad", "option_c": "Un conector de fibra", "option_d": "Un tipo de batería", "correct_answer": "b", "difficulty": "easy", "explanation": "Se recomienda desactivarlo para evitar hackeos sencillos mediante PIN."},
    {"text": "En redes, ¿qué es el 'Handshake'?", "option_a": "Darse la mano", "option_b": "Proceso de negociación inicial entre dos equipos para establecer los parámetros de la conexión", "option_c": "Un virus", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "easy", "explanation": "Como el saludo de 3 pasos (SYN, SYN-ACK, ACK) en TCP."},

